// VPS Generator — génère un fichier Excel individuel par personne
// Cellule-map (0-indexed en openpyxl, mais xlsx utilise A1):
//   B2  — Document réalisé par {auteur}
//   E4  — Remarque (optionnel)
//   C11 — NOM audité
//   C12 — SITE
//   VPS1: auditeur=F12, date=F13, état=col E, porté=col F  (lignes 15-50)
//   VPS2: auditeur=H12, date=H13, état=col G, porté=col H
//   VPS3: auditeur=J12, date=J13, état=col I, porté=col J
//   VPS4: auditeur=L12, date=L13, état=col K, porté=col L
//   VPS5: auditeur=N12, date=N13, état=col M, porté=col N

let XLSX;
try {
  XLSX = require('xlsx');
} catch (e) {
  // Fallback chemin absolu (n8n 2.7.3, avant redéploiement avec xlsx dans NODE_FUNCTION_ALLOW_EXTERNAL)
  XLSX = require('/usr/local/lib/node_modules/n8n/node_modules/xlsx');
}

const body           = $('Webhook').first().json.body;
const items          = body.items          || [];
const metadataAuthor = body.metadata_author  || 'System';
const metadataCreator= body.metadata_creator || metadataAuthor;
const rawDate        = body.metadata_date    || new Date().toISOString().split('T')[0];
const metadataDate   = new Date(rawDate + 'T12:00:00');
const outputFolder   = (body.output_folder || 'Simu/Generated').replace(/^\/|\/$/g, '');
const templateSheet  = body.template_sheet || 'Fiche_VPS.2';

const templateBinary = $input.first().binary.data;
const templateBuffer = Buffer.from(templateBinary.data, 'base64');

const VPS_COLS = [
  { auditeur: 'F12', date: 'F13', etat: 'E', porte: 'F' },
  { auditeur: 'H12', date: 'H13', etat: 'G', porte: 'H' },
  { auditeur: 'J12', date: 'J13', etat: 'I', porte: 'J' },
  { auditeur: 'L12', date: 'L13', etat: 'K', porte: 'L' },
  { auditeur: 'N12', date: 'N13', etat: 'M', porte: 'N' },
];

const results = [];

for (const item of items) {
  const wb = XLSX.read(templateBuffer, {
    type: 'buffer',
    cellStyles: true,
    cellDates: true,
    cellNF: true,
  });

  if (!wb.Sheets[templateSheet]) {
    throw new Error(`Feuille "${templateSheet}" introuvable. Disponibles: ${wb.SheetNames.join(', ')}`);
  }

  // Clonage profond — préserve merges, styles, largeurs de colonnes
  const ws = JSON.parse(JSON.stringify(wb.Sheets[templateSheet]));

  const nomAudite = item.nom_audite       || 'FICHE';
  const siteAudit = item.site             || '';
  const docAuteur = item.auteur_document  || metadataCreator;

  // En-tête
  ws['B2']  = { v: `Document réalisé par ${docAuteur}.`, t: 's' };
  ws['C11'] = { v: nomAudite, t: 's' };
  ws['C12'] = { v: siteAudit, t: 's' };

  if (item.remarque) {
    ws['E4'] = { v: item.remarque, t: 's' };
  } else {
    delete ws['E4'];
    delete ws['E5'];
  }

  // Remplissage VPS 1-5
  const vpsSessions = Array.isArray(item.vps) ? item.vps : [];
  for (let idx = 0; idx < 5; idx++) {
    const vps  = vpsSessions[idx];
    const cols = VPS_COLS[idx];
    if (!vps) continue;

    if (vps.auditeur) ws[cols.auditeur] = { v: vps.auditeur, t: 's' };

    if (vps.date) {
      const d = new Date(vps.date + 'T00:00:00');
      ws[cols.date] = { v: d, t: 'd', z: 'dd/mm/yyyy' };
    }

    const epiMode   = vps.epi_mode   || '';
    const epiValues = vps.epi_values || {};

    for (let row = 15; row <= 50; row++) {
      const typeCell = ws[`B${row}`];
      if (!typeCell || !typeCell.v) continue;

      let etat = '', porte = '';

      if (epiMode === 'OK') {
        etat = 'OK'; porte = 'OK';
      } else if (epiMode === 'NON') {
        etat = 'NON'; porte = 'NON';
      } else if (epiMode === 'random') {
        etat  = Math.random() > 0.15 ? 'OK' : 'NON';
        porte = Math.random() > 0.15 ? 'OK' : 'NON';
      } else if (epiValues[String(row)]) {
        etat  = epiValues[String(row)].etat  || '';
        porte = epiValues[String(row)].porte || '';
      }

      if (etat)  ws[`${cols.etat}${row}`]  = { v: etat,  t: 's' };
      if (porte) ws[`${cols.porte}${row}`] = { v: porte, t: 's' };
    }
  }

  // Nouveau workbook mono-feuille (fichier individuel)
  const newWb = {
    SheetNames: [nomAudite],
    Sheets: { [nomAudite]: ws },
    Props: {
      Author:       metadataCreator,
      LastAuthor:   metadataAuthor,
      CreatedDate:  metadataDate,
      ModifiedDate: metadataDate,
      Title:        `VPS - ${nomAudite}`,
      Subject:      `Visite Prévention Sécurité - ${siteAudit}`,
      Company:      'TELEHOUSE',
      Application:  'VPS Generator',
    },
  };

  const outBuffer = XLSX.write(newWb, {
    type:        'buffer',
    bookType:    'xlsx',
    cellStyles:  true,
    cellDates:   true,
    compression: true,
  });

  // Nom de fichier safe (sans accents, sans caractères spéciaux)
  const safeNom    = nomAudite
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9\s_-]/g, '').trim()
    .replace(/\s+/g, '_');
  const dateSuffix = rawDate.replace(/-/g, '');
  const filename   = `VPS_${safeNom}_${dateSuffix}.xlsx`;

  results.push({
    json: {
      filename,
      nom_audite:    nomAudite,
      site:          siteAudit,
      output_folder: outputFolder,
      upload_url:    `https://drop.ewutelo.cloud/${outputFolder}/${filename}`,
    },
    binary: {
      data: {
        data:     outBuffer.toString('base64'),
        mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        fileName: filename,
        fileSize: outBuffer.length,
      },
    },
  });
}

return results;
